=== ./s3/s3.js ===
const S3rver = require("s3rver");

const S3 = new S3rver({
    port: 8333,
    address: "0.0.0.0",
    silent: false,
    directory: "./buckets",
    vhostBuckets: false,
    serviceEndpoint: "s3"
}).run((err, { address, port } = {}) => {
    if (err) {
      console.error(err);
    } else {
      console.log("Fake S3 server listening at address %s and port %d", address, port);
    }
});
