worker_processes auto;

events {
    worker_connections 1024;
}

http {
    client_header_buffer_size 16k;
    large_client_header_buffers 4 32k;
    client_max_body_size 8m;

    server {
        listen 80;

        location / {
            proxy_pass http://frontend:3000;
